// Bundle Output â€” assemble final shape.
// Reads parse prompts (override||default) and config from named upstream nodes,
// substitutes {placeholders}, packages by agent. Output contract unchanged:
//   { prompts: { agent_1..agent_9 }, prompt_warnings, config }
const promptItems = $('Parse Prompts').all();
const configItem = $('Parse Config').first();
const config = (configItem && configItem.json && configItem.json.config) || {};
const prompts = {};
const prompt_warnings = [];
for (const item of promptItems) {
  const { agent_id, text, warnings } = item.json;
  if (warnings && warnings.length > 0) {
    prompt_warnings.push(...warnings);
  }
  if (agent_id === null || agent_id === undefined || agent_id === '') continue;
  // Substitute {config_key} placeholders
  const body = String(text || '').replace(/\{([a-z_][a-z_0-9]*)\}/gi, (full, key) => {
    if (config[key] !== undefined && config[key] !== null && config[key] !== '') {
      return String(config[key]);
    }
    prompt_warnings.push({
      agent: agent_id,
      issue: `Unresolved placeholder: {${key}}`
    });
    return full;
  });
  prompts[agent_id] = body;
}
console.log(`[Prompt Loader] Loaded ${Object.keys(prompts).length} prompts`);
console.log(`[Prompt Loader] Config keys: ${Object.keys(config).length}`);
console.log(`[Prompt Loader] Warnings: ${prompt_warnings.length}`);
return [{ json: { prompts, prompt_warnings } }];

// Prompt Loader â€” find Database workbook in root folder
// (Agent Prompts folder no longer needed; prompts now live in the `prompts` sheet tab.)

const items = $input.all().map(i => i.json);

const findOne = (name) => {
  const matches = items.filter(i => i.name === name);
  if (matches.length === 0) {
    const available = items.length
      ? items.map(i => `  - "${i.name}"`).join('\n')
      : '  (folder is empty)';
    throw new Error(
      `[Prompt Loader] Could not find "${name}" in root folder.\n` +
      `Available items:\n${available}`
    );
  }
  if (matches.length > 1) {
    throw new Error(`[Prompt Loader] Multiple items named "${name}" found. Names must be unique.`);
  }
  return matches[0].id;
};

const database_id = findOne('Database');

console.log(`[Prompt Loader] Resolved database_id: ${database_id}`);

return [{ json: { database_id } }];

// Parse Config â€” build clean config object from sheet rows
const stripEquals = (val) => {
  if (typeof val !== 'string') return val;
  return val.startsWith('=') ? val.substring(1) : val;
};
const items = $input.all();
const config = {};
for (const item of items) {
  const j = item.json;
  const param = (j.parameter ?? j.Parameter ?? '').toString().trim();
  let value = j.value !== undefined ? j.value : j.Value;
  value = stripEquals(value);
  if (param) config[param] = value;
}
console.log(`[Parse Config] Loaded ${Object.keys(config).length} config keys`);
return [{ json: { config } }];

// Resolve Prompts â€” read the `prompts` tab rows, pick override || default per agent.
// Emits one item per agent: { agent_id, text, source } where source = 'override' | 'default'.
// Reset = clearing override_markdown in the sheet (handled by the frontend), so blank/whitespace override falls back to default.

const stripEquals = (val) => {
  if (typeof val !== 'string') return val;
  return val.startsWith('=') ? val.substring(1) : val;
};

const items = $input.all();
const results = [];
const warnings = [];

for (const item of items) {
  const j = item.json;
  const agent_id = (j.agent_id ?? j.Agent_id ?? '').toString().trim();
  if (!agent_id) {
    warnings.push({ issue: 'Row with blank agent_id skipped' });
    continue;
  }

  const def = stripEquals(j.default_markdown ?? j.Default_markdown ?? '') || '';
  const ovrRaw = stripEquals(j.override_markdown ?? j.Override_markdown ?? '') || '';
  const ovr = typeof ovrRaw === 'string' ? ovrRaw : String(ovrRaw);

  const useOverride = ovr.trim().length > 0;
  const text = useOverride ? ovr : def;
  const source = useOverride ? 'override' : 'default';

  if (!text || !text.trim()) {
    warnings.push({ agent: agent_id, issue: 'Empty prompt (no override and no default)' });
  }

  results.push({ json: { agent_id, text, source, warnings: [] } });
}

// attach accumulated warnings to the first item so Bundle Output can surface them
if (results.length > 0) {
  results[0].json.warnings = warnings;
} else {
  results.push({ json: { agent_id: null, text: '', source: 'none', warnings } });
}

console.log(`[Parse Prompts] ${results.length} prompt row(s); ` +
  results.map(r => `${r.json.agent_id}=${r.json.source}`).join(', '));

return results;
